def solve(patent_applications, prior_art):
    if not isinstance(patent_applications, list) or not isinstance(prior_art, list):
        raise ValueError("Both patent_applications and prior_art must be lists.")

    # Assuming the core logic is to transpose prior art into patent applications
    for application in patent_applications:
        if not isinstance(application, dict):
            raise ValueError("Each patent application must be a dictionary.")

        # Transpose prior art into the application
        application['prior_art'] = [art for art in prior_art if art['application_id'] == application['id']]

    return patent_applications
